export function nextGeneration(cells: Cell[]): Cell[] {
  const liveCells = new Set(cells.map(([x, y]) => key(x, y)));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    candidates.set(key(x, y), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      candidates.set(key(x + dx, y + dy), [x + dx, y + dy]);
    }
  }
  const result: Cell[] = [];
  for (const [k, [x, y]] of candidates) {
    const liveNeighbors = countLiveNeighbors(x, y, liveCells);
    const isAlive = liveCells.has(k);
    if (isAlive && (liveNeighbors === 2 || liveNeighbors === 3)) {
      result.push([x, y]);
    } else if (!isAlive && liveNeighbors === 3) {
      result.push([x, y]);
    }
  }
  return result;
}

